import {
  SSMClient,
  GetParameterCommand,
  GetParametersByPathCommand,
} from "@aws-sdk/client-ssm";
import {
  SecretsManagerClient,
  GetSecretValueCommand,
} from "@aws-sdk/client-secrets-manager";

const ssmClient = new SSMClient({ region: process.env.AWS_REGION });
const secretsClient = new SecretsManagerClient({
  region: process.env.AWS_REGION,
});

// Cache for parameters to avoid repeated API calls
const parameterCache = new Map();
const secretCache = new Map();

/**
 * Get parameter from Systems Manager Parameter Store with caching
 */
async function getParameter(parameterName, decrypt = false) {
  const cacheKey = `${parameterName}:${decrypt}`;

  if (parameterCache.has(cacheKey)) {
    return parameterCache.get(cacheKey);
  }

  try {
    const command = new GetParameterCommand({
      Name: parameterName,
      WithDecryption: decrypt,
    });

    const response = await ssmClient.send(command);
    const value = response.Parameter?.Value;

    parameterCache.set(cacheKey, value);
    return value;
  } catch (error) {
    console.warn(`Failed to get parameter ${parameterName}:`, error.message);
    return null;
  }
}

/**
 * Get multiple parameters by path from Systems Manager Parameter Store
 */
async function getParametersByPath(path, decrypt = false) {
  if (parameterCache.has(path)) {
    return parameterCache.get(path);
  }

  try {
    const command = new GetParametersByPathCommand({
      Path: path,
      Recursive: true,
      WithDecryption: decrypt,
    });

    const response = await ssmClient.send(command);
    const parameters = {};

    response.Parameters?.forEach((param) => {
      const key = param.Name?.replace(path, "").replace(/^\//, "");
      parameters[key] = param.Value;
    });

    parameterCache.set(path, parameters);
    return parameters;
  } catch (error) {
    console.warn(`Failed to get parameters by path ${path}:`, error.message);
    return {};
  }
}

/**
 * Get secret from AWS Secrets Manager with caching
 */
async function getSecret(secretName) {
  if (secretCache.has(secretName)) {
    return secretCache.get(secretName);
  }

  try {
    const command = new GetSecretValueCommand({
      SecretId: secretName,
    });

    const response = await secretsClient.send(command);
    const secretValue = response.SecretString
      ? JSON.parse(response.SecretString)
      : null;

    secretCache.set(secretName, secretValue);
    return secretValue;
  } catch (error) {
    console.warn(`Failed to get secret ${secretName}:`, error.message);
    return null;
  }
}

/**
 * Get configuration value from Parameter Store
 */
async function getConfigValue(parameterName, defaultValue = null) {
  const value = await getParameter(parameterName);
  return value !== null ? value : defaultValue;
}

/**
 * Load service configuration from Parameter Store for a specific tenant
 */
async function loadServiceConfig(tenantId = "default") {
  const basePath = `/apersona/${tenantId}`;

  return {
    serviceName: await getConfigValue(
      `${basePath}/service/name`,
      "CompanyName"
    ),
    asmUrl: await getConfigValue(`${basePath}/asm/service_url`),
    asmPortalUrl: await getConfigValue(`${basePath}/asm/portal_url`),
    asmPolicies: await getConfigValue(`${basePath}/asm/policies`),
    rootDomainName: await getConfigValue(`${basePath}/domain/root`),
    adminEmail: await getConfigValue(`${basePath}/admin/email`),
    spPortalUrl: await getConfigValue(`${basePath}/sp/portal_url`),
    extraAppUrl: await getConfigValue(`${basePath}/extra/app_url`),
  };
}

/**
 * Load branding configuration from Parameter Store for a specific tenant
 */
async function loadBrandingConfig(tenantId = "default") {
  const basePath = `/apersona/${tenantId}/branding`;

  const brandingParams = await getParametersByPath(basePath);

  return {
    service_name:
      brandingParams.service_name ||
      (await getConfigValue(
        `/apersona/${tenantId}/service/name`,
        "CompanyName"
      )),
    mobile_token_svc_name:
      brandingParams.mobile_token_svc_name ||
      brandingParams.service_name ||
      (await getConfigValue(
        `/apersona/${tenantId}/service/name`,
        "CompanyName"
      )),
    logo_url:
      brandingParams.logo_url ||
      "https://downloads.apersona.com/logos/logo-here_250x50.png",
    email_logo_url:
      brandingParams.email_logo_url ||
      "https://downloads.apersona.com/logos/logo-here_250x50.png",
    brand_base_color: brandingParams.brand_base_color || "#7D8CA3",
    favicon_url:
      brandingParams.favicon_url ||
      "https://downloads.apersona.com/logos/favicon.png",
  };
}

/**
 * Load legal configuration from Parameter Store for a specific tenant
 */
async function loadLegalConfig(tenantId = "default") {
  const basePath = `/apersona/${tenantId}/legal`;

  const legalParams = await getParametersByPath(basePath);

  return {
    terms_of_service:
      legalParams.terms_of_service ||
      "https://downloads.apersona.com/demos/company-Ts-Cs.html",
    privacy_policy:
      legalParams.privacy_policy ||
      "https://downloads.apersona.com/demos/company-privacy.html",
  };
}

/**
 * Load AMFA configuration from Parameter Store for a specific tenant
 */
async function loadAmfaConfig(tenantId = "default") {
  const basePath = `/apersona/${tenantId}/amfa`;

  const amfaParams = await getParametersByPath(basePath);
  const serviceConfig = await loadServiceConfig(tenantId);

  // Parse JSON arrays from parameter store
  const parseJsonParam = (param, defaultValue) => {
    if (!param) return defaultValue;
    try {
      return JSON.parse(param);
    } catch (error) {
      console.warn(`Failed to parse JSON parameter:`, error.message);
      return defaultValue;
    }
  };

  return {
    "COMMENT-File":
      "This file contains the available primary AWS aPersona Adaptive MFA login settings.",
    asmurl: serviceConfig.asmUrl,
    asm_portal_url: serviceConfig.asmPortalUrl,
    enable_password_reset: amfaParams.enable_password_reset === "true" || true,
    enable_self_service: amfaParams.enable_self_service === "true" || true,
    enable_self_service_remove_buttons:
      amfaParams.enable_self_service_remove_buttons === "true" || true,
    enable_user_registration:
      amfaParams.enable_user_registration === "true" || true,
    enable_have_i_been_pwned:
      amfaParams.enable_have_i_been_pwned === "true" || true,
    enable_google_recaptcha:
      amfaParams.enable_google_recaptcha === "true" || false,
    "COMMENT-NOTE!!! Please Take care of using 'master_additional_otp_methods'":
      " 'e' would be always available for update profile and password reset, even if 'e' is not set. Available options are: 'e' for primary email, 'ae' for alt-email, 's' for sms, 'v' for voice, 't' for mobile soft token. Be sure to use double quotes.",
    master_additional_otp_methods: parseJsonParam(
      amfaParams.master_additional_otp_methods,
      ["e", "ae", "s", "v", "t"]
    ),
    user_registration_default_group:
      amfaParams.user_registration_default_group || "user",
    update_profile_force_mobile_token_first_if_registered:
      amfaParams.update_profile_force_mobile_token_first_if_registered ===
        "true" || true,
    "COMMENT-totp":
      "The totp secrets and integration provider ID are located in the AWS secret manager",
    enable_password_expire:
      amfaParams.enable_password_expire === "true" || true,
    passwords_expire_days: parseInt(amfaParams.passwords_expire_days) || 90,
    enable_prevent_password_reuse:
      amfaParams.enable_prevent_password_reuse === "true" || true,
    prevent_password_reuse_count:
      parseInt(amfaParams.prevent_password_reuse_count) || 5,
    enable_auto_pwd_reset_on_threat:
      amfaParams.enable_auto_pwd_reset_on_threat === "true" || true,
  };
}

/**
 * Discover all tenant IDs from Parameter Store
 */
async function discoverTenants() {
  try {
    const command = new GetParametersByPathCommand({
      Path: "/apersona",
      Recursive: false,
      WithDecryption: false,
    });

    const response = await ssmClient.send(command);
    const tenantIds = new Set();

    response.Parameters?.forEach((param) => {
      const pathParts = param.Name.split("/");
      if (pathParts.length >= 3) {
        const tenantId = pathParts[2];
        if (tenantId && tenantId !== "secrets") {
          tenantIds.add(tenantId);
        }
      }
    });

    const tenants = Array.from(tenantIds);
    console.log("Discovered tenants:", tenants);

    // If no tenants found, use default
    return tenants.length > 0 ? tenants : ["default"];
  } catch (error) {
    console.warn("Failed to discover tenants, using default:", error.message);
    return ["default"];
  }
}

/**
 * Load configuration for a specific tenant
 */
export const loadTenantConfiguration = async (tenantId = "default") => {
  const [serviceConfig, amfaConfigs, amfaBrandings, amfaLegals] =
    await Promise.all([
      loadServiceConfig(tenantId),
      loadAmfaConfig(tenantId),
      loadBrandingConfig(tenantId),
      loadLegalConfig(tenantId),
    ]);

  return {
    tenantId,
    serviceConfig,
    amfaConfigs,
    amfaBrandings,
    amfaLegals,
    amfaPolicies: serviceConfig.asmPolicies,
  };
};

/**
 * Load configurations for all tenants
 */
export const loadAllTenantsConfiguration = async () => {
  console.log("Loading configurations for all tenants...");

  const tenantIds = await discoverTenants();
  console.log(`Found ${tenantIds.length} tenant(s): ${tenantIds.join(", ")}`);

  const tenantConfigurations = {};

  // Load configuration for each tenant
  for (const tenantId of tenantIds) {
    try {
      console.log(`Loading configuration for tenant: ${tenantId}`);
      tenantConfigurations[tenantId] = await loadTenantConfiguration(tenantId);
    } catch (error) {
      console.error(
        `Failed to load configuration for tenant ${tenantId}:`,
        error.message
      );
      // Continue with other tenants even if one fails
    }
  }

  console.log(
    `Successfully loaded configurations for ${
      Object.keys(tenantConfigurations).length
    } tenant(s)`
  );
  return tenantConfigurations;
};

