import { DynamoDBClient, PutItemCommand, GetItemCommand } from "@aws-sdk/client-dynamodb";

import {
  CognitoIdentityProviderClient,
  CreateGroupCommand,
  DescribeUserPoolCommand,
  UpdateUserPoolCommand,
} from "@aws-sdk/client-cognito-identity-provider";

import { SSMClient, GetParametersByPathCommand } from "@aws-sdk/client-ssm";
import { 
  loadAllTenantsConfiguration,
  DEFAULT_AMFA_CONFIG,
  DEFAULT_BRANDING_CONFIG,
  DEFAULT_LEGAL_CONFIG
} from "./config.mjs";

const dynamodb = new DynamoDBClient({ region: process.env.AWS_REGION });
const cognito = new CognitoIdentityProviderClient({
  region: process.env.AWS_REGION,
});
const ssmClient = new SSMClient({ region: process.env.AWS_REGION });

const createUserGroup = async (GroupName, UserPoolId) => {
  const param = {
    GroupName,
    UserPoolId,
  };
  await cognito.send(new CreateGroupCommand(param));
};

const createAmfaConfigsWithValues = async (configType, dynamodb, values, tenantId) => {
  console.log(`createAmfaConfigsWithValues for tenant ${tenantId}, configType: ${configType}`);

  let value = "";

  if (configType === "amfaPolicies") {
    value = values[configType];
    if (value !== "" && value !== "null") {
      try {
        value = JSON.parse(value);
        for (const key in value) {
          const policy = value[key];
          const child = {};
          child["policy_name"] = policy;
          const sp = policy.split("-");
          child["enable_passwordless"] = true;
          child["permissions"] = ["e", "ae", "s", "v", "t"];
          child["rank"] = isNaN(parseInt(sp[1])) ? "" : parseInt(sp[1]);
          value[key] = child;

          // Note: User groups for policies will be created per tenant in the main handler
        }
        value = JSON.stringify(value, null, "  ");
      } catch (e) {
        console.log("amfaPolicy parsing error");
        value = "";
      }
    } else {
      value = "";
    }
  } else {
    try {
      value = JSON.stringify(values[configType], null, "  ");
    } catch (error) {
      console.log("amfaConfig parsing error");
    }
  }

  if (value === "" || value === "null") {
    console.log("no value for ", configType);
    return;
  }

  console.log(`createAmfaConfigs configType: ${configType}, value: ${value}`);

  try {
    // Check if config already exists for this tenant
    const getParams = {
      Key: {
        id: {
          S: tenantId,
        },
        configtype: {
          S: configType,
        },
      },
      TableName: process.env.AMFACONFIG_TABLE,
    };

    let existingItem;
    try {
      const getResult = await dynamodb.send(new GetItemCommand(getParams));
      existingItem = getResult.Item;
    } catch (getErr) {
      console.log(`No existing config found for tenant ${tenantId}, configType ${configType}`);
      existingItem = null;
    }

    if (existingItem) {
      console.log(`Config already exists for tenant ${tenantId}, configType ${configType}. Skipping to avoid overriding.`);
      return;
    }

    // Config doesn't exist, create it
    const params = {
      Item: {
        id: {
          S: tenantId,
        },
        configtype: {
          S: configType,
        },
        value: {
          S: value,
        },
      },
      ReturnConsumedCapacity: "TOTAL",
      TableName: process.env.AMFACONFIG_TABLE,
    };

    console.log("createAmfaConfigs params", params);

    let putItemCommand = new PutItemCommand(params);
    let results = await dynamodb.send(putItemCommand);
    console.log(`${configType} write result for tenant ${tenantId}:`, results);
  } catch (err) {
    console.error(`create config failed for tenant ${tenantId}:`, err);
    console.error("RequestId: " + err.requestId);
  }
};

const switchUserpoolTierToLite = async (UserPoolId) => {
  const describeUserPoolRes = await cognito.send(
    new DescribeUserPoolCommand({
      UserPoolId,
    })
  );

  const userPool = describeUserPoolRes.UserPool;
  if (!userPool) {
    throw new Error("UserPool not found");
  }

  if (userPool.UserPoolTier === "LITE") {
    console.log("UserPool already in LITE tier");
    return;
  }

  userPool.UserPoolTier = "LITE";
  delete userPool.CreationDate;
  delete userPool.LastModifiedDate;
  delete userPool.EstimatedNumberOfUsers;
  delete userPool.Id;
  delete userPool.Status;

  const param = {
    UserPoolId,
    ...userPool,
  };

  return cognito.send(new UpdateUserPoolCommand(param));
};

/**
 * Load tenant configurations from Parameter Store (JSON format)
 * Each tenant has a single parameter: /apersona/tenants/{tenant_id}/config
 * containing JSON with: name, contact, url, sp_portal_url, extra_app_url, saml_proxy
 */
const loadTenantsFromParameterStore = async () => {
  try {
    const command = new GetParametersByPathCommand({
      Path: "/apersona/tenants",
      Recursive: true,
      WithDecryption: false,
    });

    const response = await ssmClient.send(command);
    const tenantMap = {};

    // Parse each parameter (expecting JSON format)
    response.Parameters?.forEach((param) => {
      const pathParts = param.Name.split("/");
      // Path format: /apersona/tenants/{tenant_id}/config
      if (pathParts.length === 5 && pathParts[4] === "config") {
        const tenantId = pathParts[3];

        try {
          // Parse JSON configuration
          const config = JSON.parse(param.Value);
          tenantMap[tenantId] = {
            tenant_id: tenantId,
            name: config.name || tenantId,
            contact: config.contact || "",
            url:
              config.url ||
              `https://${tenantId}.idapersona.${
                process.env.ROOT_DOMAIN_NAME || "example.com"
              }`,
            endUserSpUrl:
              config.sp_portal_url ||
              `https://${tenantId}.login.${
                process.env.ROOT_DOMAIN_NAME || "example.com"
              }`,
            extraAppUrl: config.extra_app_url || "",
            samlproxy:
              config.saml_proxy !== undefined ? config.saml_proxy : true,
          };
        } catch (error) {
          console.error(
            `Failed to parse config for tenant ${tenantId}:`,
            error
          );
        }
      }
    });

    console.log("Loaded tenants from Parameter Store:", Object.keys(tenantMap));
    return tenantMap;
  } catch (error) {
    console.warn("Failed to load tenants from Parameter Store:", error.message);
    return {};
  }
};

const createTenants = async (dynamodb, ssmTenantsInfo) => {
  console.log("createTenants - using SSM tenant configurations and user pools");

  // Get tenant user pools from environment variable
  const tenantUserPools = JSON.parse(process.env.TENANT_USER_POOLS || "{}");
  console.log("Tenant user pools:", tenantUserPools);

  for (const [tenantId, tenantUserPoolInfo] of Object.entries(
    tenantUserPools
  )) {
    try {
      // Get tenant info from SSM Parameter Store
      const ssmTenantInfo = ssmTenantsInfo[tenantId];

      // Build tenant info from SSM and CDK, with fallbacks for missing SSM data
      const tenant = {
        tenant_id: tenantId,
        name: ssmTenantInfo?.name || tenantUserPoolInfo.tenantName || tenantId,
        contact: ssmTenantInfo?.contact || "",
        url:
          ssmTenantInfo?.url ||
          `https://${tenantId}.idapersona.${
            process.env.ROOT_DOMAIN_NAME || "example.com"
          }`,
        endUserSpUrl:
          ssmTenantInfo?.endUserSpUrl ||
          `https://${tenantId}.login.${
            process.env.ROOT_DOMAIN_NAME || "example.com"
          }`,
        extraAppUrl: ssmTenantInfo?.extraAppUrl || "",
        samlproxy:
          ssmTenantInfo?.samlproxy !== undefined
            ? ssmTenantInfo.samlproxy
            : true,
        endUserClientId: tenantUserPoolInfo.endUserClientId || "",
      };

      console.log(`Creating tenant record for ${tenantId}:`, tenant);

      const params = {
        Item: {
          id: {
            S: tenant.tenant_id,
          },
          name: {
            S: tenant.name,
          },
          contact: {
            S: tenant.contact,
          },
          url: {
            S: tenant.url,
          },
          endUserSpUrl: {
            S: tenant.endUserSpUrl,
          },
          extraappurl: {
            S: tenant.extraAppUrl,
          },
          samlproxy: {
            BOOL: tenant.samlproxy,
          },
          samlIdPMetadataUrl: {
            S: `https://samlproxy.apersona-id.com/Saml2IDP/proxy.xml`,
          },
          userpool: {
            S: tenantUserPoolInfo.userPoolId,
          },
          enduserclientid: {
            S: tenant.endUserClientId,
          },
        },
        ReturnConsumedCapacity: "TOTAL",
        TableName: process.env.AMFATENANT_TABLE,
      };
      let results = await dynamodb.send(new PutItemCommand(params));
      console.log(`amfa tenant write result for ${tenantId}:`, results);
    } catch (err) {
      console.error(`create amfa tenant item failed for ${tenantId}:`, err);
      console.error("RequestId: " + err.requestId);
    }
  }
};

